/// <summary>
/// This is an service class for CapexApprovalId
/// </summary>
internal final class ETGCapexIdService extends SysOperationServiceBase
{
}

Method.Source:
/// <summary>
/// This method processes the business logic.
/// </summary>
public void process()
{
    VendInvoiceJour             vendInvoiceJour;
    PurchLine                   purchLine;
    GeneralJournalAccountEntry  generalJournalAccountEntry;
    GeneralJournalEntry         generalJournalEntry;
    QueryRun                    queryRun;

    if(AssetParameters::find().ETGCapexApprovalIdFeature == NoYes::Yes)
    {
        queryRun = new QueryRun(queryStr(ETGCapexApprovalIdQuery));
        ttsbegin;
        while(queryRun.next())
        {
            purchLine                   = queryRun.get(tableNum(PurchLine));
            generalJournalAccountEntry  = queryRun.get(tableNum(GeneralJournalAccountEntry));
            generalJournalEntry         = queryRun.get(tableNum(GeneralJournalEntry));
            vendinvoiceJour             =  queryRun.get(tableNum(VendInvoiceJour));

            generalJournalAccountEntry.selectForUpdate(true);
            generalJournalAccountEntry.ETGCapexApprovalId = purchLine.ETGCapexApprovalId;
            generalJournalAccountEntry.doUpdate();

            if(vendInvoiceJour.ETGCapexIdUpdated == NoYes::No)
            {
                vendInvoiceJour.selectForUpdate(true);
                vendInvoiceJour.reread();
                vendInvoiceJour.ETGCapexIdUpdated = NoYes::Yes;
                vendInvoiceJour.doUpdate();
            }
        }
        ttscommit;

    }

}
